import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Plus, Search, Edit2, Trash2, Bell, X, CheckCircle, XCircle } from 'lucide-react';
import API from '../../utils/api';
import AdminLayout from './AdminLayout';
import toast from 'react-hot-toast';

const PLANS = ['monthly', 'quarterly', 'half-yearly', 'yearly'];

const emptyForm = {
  name: '', email: '', phone: '', whatsapp: '', password: '',
  membershipPlan: 'monthly', membershipStart: '', membershipEnd: '',
  feeAmount: '', assignedTrainer: '', gender: '', dob: '', address: ''
};

export default function AdminMembers() {
  const [members, setMembers] = useState([]);
  const [trainers, setTrainers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [editId, setEditId] = useState(null);
  const [notifModal, setNotifModal] = useState(null);
  const [notifForm, setNotifForm] = useState({ title: '', message: '', sendWhatsApp: true });
  const [filterStatus, setFilterStatus] = useState('all');

  const load = () => {
    API.get('/members').then(r => setMembers(r.data)).catch(() => {}).finally(() => setLoading(false));
    API.get('/trainers').then(r => setTrainers(r.data)).catch(() => {});
  };
  useEffect(load, []);

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSave = async () => {
    try {
      if (editId) { await API.put(`/members/${editId}`, form); toast.success('Member updated'); }
      else { await API.post('/members', form); toast.success('Member added'); }
      setModal(false); setForm(emptyForm); setEditId(null); load();
    } catch (err) { toast.error(err.response?.data?.message || 'Error'); }
  };

  const openEdit = (m) => {
    setForm({
      name: m.name, email: m.email, phone: m.phone, whatsapp: m.whatsapp || '',
      membershipPlan: m.membershipPlan, feeAmount: m.feeAmount,
      membershipStart: m.membershipStart?.split('T')[0] || '',
      membershipEnd: m.membershipEnd?.split('T')[0] || '',
      assignedTrainer: m.assignedTrainer?._id || '',
      gender: m.gender || '', dob: m.dob?.split('T')[0] || '', address: m.address || '',
      membershipStatus: m.membershipStatus
    });
    setEditId(m._id); setModal(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this member?')) return;
    try { await API.delete(`/members/${id}`); toast.success('Deleted'); load(); }
    catch { toast.error('Error deleting'); }
  };

  const sendNotif = async () => {
    try {
      await API.post(`/members/${notifModal}/send-notification`, notifForm);
      toast.success('Notification sent!');
      setNotifModal(null);
      setNotifForm({ title: '', message: '', sendWhatsApp: true });
    } catch { toast.error('Failed to send notification'); }
  };

  const filtered = members.filter(m => {
    const matchSearch = m.name.toLowerCase().includes(search.toLowerCase()) || m.phone.includes(search);
    const matchStatus = filterStatus === 'all' || m.membershipStatus === filterStatus;
    return matchSearch && matchStatus;
  });

  return (
    <AdminLayout title="Members Management">
      {/* Top bar */}
      <div className="flex flex-col sm:flex-row gap-4 mb-6 items-start sm:items-center justify-between">
        <div className="flex gap-3 flex-1">
          <div className="relative flex-1 max-w-xs">
            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
            <input className="input-dark pl-9 text-sm py-2.5" placeholder="Search members..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>
          <select className="input-dark text-sm py-2.5 w-36" value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
            <option value="all">All Status</option>
            <option value="active">Active</option>
            <option value="expired">Expired</option>
            <option value="pending">Pending</option>
          </select>
        </div>
        <button onClick={() => { setModal(true); setEditId(null); setForm(emptyForm); }} className="btn-fire flex items-center gap-2 text-sm py-2.5 px-4">
          <Plus size={16} /> Add Member
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><div className="w-10 h-10 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" /></div>
      ) : (
        <div className="glass rounded-xl overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="border-b border-white/10">
                <tr className="text-gray-500 text-xs uppercase">
                  {['Name', 'Phone', 'Plan', 'Expires', 'Status', 'Trainer', 'Actions'].map(h => (
                    <th key={h} className="text-left px-4 py-3 font-semibold">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr><td colSpan={7} className="text-center py-12 text-gray-500">No members found</td></tr>
                ) : filtered.map((m, i) => {
                  const daysLeft = m.membershipEnd ? Math.ceil((new Date(m.membershipEnd) - new Date()) / (1000 * 60 * 60 * 24)) : null;
                  return (
                    <tr key={m._id} className="border-b border-white/5 hover:bg-white/2 transition-colors">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-orange-500 to-red-500 flex items-center justify-center text-white font-bold text-xs">
                            {m.name?.[0]?.toUpperCase()}
                          </div>
                          <div>
                            <div className="text-white font-medium">{m.name}</div>
                            <div className="text-gray-500 text-xs">{m.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-gray-300">{m.phone}</td>
                      <td className="px-4 py-3 text-gray-300 capitalize">{m.membershipPlan}</td>
                      <td className="px-4 py-3">
                        <div className="text-gray-300 text-xs">{m.membershipEnd ? new Date(m.membershipEnd).toLocaleDateString() : '—'}</div>
                        {daysLeft !== null && daysLeft >= 0 && daysLeft <= 7 && (
                          <div className={`text-xs font-semibold ${daysLeft <= 3 ? 'text-red-400' : 'text-yellow-400'}`}>{daysLeft}d left</div>
                        )}
                      </td>
                      <td className="px-4 py-3">
                        <span className={`text-xs px-2 py-0.5 rounded-full capitalize font-medium ${
                          m.membershipStatus === 'active' ? 'bg-green-500/20 text-green-400' :
                          m.membershipStatus === 'expired' ? 'bg-red-500/20 text-red-400' :
                          'bg-yellow-500/20 text-yellow-400'
                        }`}>{m.membershipStatus}</span>
                      </td>
                      <td className="px-4 py-3 text-gray-400 text-xs">{m.assignedTrainer?.name || '—'}</td>
                      <td className="px-4 py-3">
                        <div className="flex gap-2">
                          <button onClick={() => setNotifModal(m._id)} title="Send Notification" className="p-1.5 text-blue-400 hover:bg-blue-400/10 rounded-lg transition-all"><Bell size={15} /></button>
                          <button onClick={() => openEdit(m)} className="p-1.5 text-orange-400 hover:bg-orange-400/10 rounded-lg transition-all"><Edit2 size={15} /></button>
                          <button onClick={() => handleDelete(m._id)} className="p-1.5 text-red-400 hover:bg-red-400/10 rounded-lg transition-all"><Trash2 size={15} /></button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Add/Edit Modal */}
      {modal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center px-4" onClick={e => { if (e.target === e.currentTarget) { setModal(false); } }}>
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
            className="bg-[#0d0d14] border border-white/10 rounded-2xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-white font-bold text-xl">{editId ? 'Edit Member' : 'Add Member'}</h2>
              <button onClick={() => setModal(false)}><X size={20} className="text-gray-400" /></button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {[
                { name: 'name', label: 'Name *', type: 'text' },
                { name: 'email', label: 'Email *', type: 'email' },
                { name: 'phone', label: 'Phone *', type: 'text' },
                { name: 'whatsapp', label: 'WhatsApp No', type: 'text' },
                { name: 'password', label: editId ? 'New Password' : 'Password', type: 'password' },
                { name: 'feeAmount', label: 'Fee Amount (₹)', type: 'number' },
                { name: 'membershipStart', label: 'Membership Start', type: 'date' },
                { name: 'membershipEnd', label: 'Membership End', type: 'date' },
                { name: 'dob', label: 'Date of Birth', type: 'date' },
                { name: 'address', label: 'Address', type: 'text' },
              ].map(f => (
                <div key={f.name}>
                  <label className="text-gray-400 text-xs block mb-1">{f.label}</label>
                  <input className="input-dark text-sm py-2" name={f.name} type={f.type} value={form[f.name]} onChange={handleChange} />
                </div>
              ))}
              <div>
                <label className="text-gray-400 text-xs block mb-1">Membership Plan</label>
                <select className="input-dark text-sm py-2" name="membershipPlan" value={form.membershipPlan} onChange={handleChange}>
                  {PLANS.map(p => <option key={p} value={p} className="bg-[#0d0d14]">{p.charAt(0).toUpperCase() + p.slice(1)}</option>)}
                </select>
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Assign Trainer</label>
                <select className="input-dark text-sm py-2" name="assignedTrainer" value={form.assignedTrainer} onChange={handleChange}>
                  <option value="">None</option>
                  {trainers.map(t => <option key={t._id} value={t._id} className="bg-[#0d0d14]">{t.name}</option>)}
                </select>
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Gender</label>
                <select className="input-dark text-sm py-2" name="gender" value={form.gender} onChange={handleChange}>
                  <option value="">Select</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                  <option value="other">Other</option>
                </select>
              </div>
              {editId && (
                <div>
                  <label className="text-gray-400 text-xs block mb-1">Status</label>
                  <select className="input-dark text-sm py-2" name="membershipStatus" value={form.membershipStatus} onChange={handleChange}>
                    <option value="active">Active</option>
                    <option value="expired">Expired</option>
                    <option value="pending">Pending</option>
                  </select>
                </div>
              )}
            </div>
            <div className="flex justify-end gap-3 mt-6">
              <button onClick={() => setModal(false)} className="px-4 py-2 text-gray-400 hover:text-white border border-white/10 rounded-lg text-sm">Cancel</button>
              <button onClick={handleSave} className="btn-fire px-5 py-2 text-sm">{editId ? 'Update' : 'Add Member'}</button>
            </div>
          </motion.div>
        </div>
      )}

      {/* Send Notification Modal */}
      {notifModal && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center px-4">
          <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }}
            className="bg-[#0d0d14] border border-white/10 rounded-2xl p-6 w-full max-w-md">
            <div className="flex items-center justify-between mb-5">
              <h2 className="text-white font-bold text-xl flex items-center gap-2"><Bell size={18} className="text-orange-400" /> Send Notification</h2>
              <button onClick={() => setNotifModal(null)}><X size={20} className="text-gray-400" /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-gray-400 text-xs block mb-1">Title</label>
                <input className="input-dark text-sm py-2" value={notifForm.title} onChange={e => setNotifForm({ ...notifForm, title: e.target.value })} placeholder="Notification title..." />
              </div>
              <div>
                <label className="text-gray-400 text-xs block mb-1">Message</label>
                <textarea className="input-dark text-sm min-h-[100px] py-2" value={notifForm.message} onChange={e => setNotifForm({ ...notifForm, message: e.target.value })} placeholder="Message content..." />
              </div>
              <label className="flex items-center gap-2 cursor-pointer">
                <input type="checkbox" checked={notifForm.sendWhatsApp} onChange={e => setNotifForm({ ...notifForm, sendWhatsApp: e.target.checked })} className="rounded" />
                <span className="text-gray-300 text-sm">Also send via WhatsApp</span>
              </label>
            </div>
            <div className="flex justify-end gap-3 mt-5">
              <button onClick={() => setNotifModal(null)} className="px-4 py-2 text-gray-400 border border-white/10 rounded-lg text-sm">Cancel</button>
              <button onClick={sendNotif} className="btn-fire px-5 py-2 text-sm flex items-center gap-2"><Bell size={15} /> Send</button>
            </div>
          </motion.div>
        </div>
      )}
    </AdminLayout>
  );
}
